import http.server
import json
import os
import threading
from datetime import datetime
from urllib.parse import urlparse, parse_qs


class LogConfig:
    """Configuration for the logging utility."""
    
    def __init__(self, log_dir="logs", default_log_file="app.log",
                 max_file_size_mb=10, backup_count=5, log_format=None):
        self.log_dir = log_dir
        self.default_log_file = default_log_file
        self.max_file_size_mb = max_file_size_mb
        self.backup_count = backup_count
        self.log_format = log_format or "[{timestamp}] [{level}] [{service}] [{request_id}] - {message}"
        
        os.makedirs(self.log_dir, exist_ok=True)


class LogWriter:
    """Thread-safe log file writer with rotation support."""
    
    def __init__(self, config):
        self.config = config
        self._lock = threading.Lock()
        self._file_handles = {}
    
    def _get_log_file_path(self, service_name=None):
        if service_name:
            filename = "{}.log".format(service_name)
        else:
            filename = self.config.default_log_file
        return os.path.join(self.config.log_dir, filename)
    
    def _rotate_if_needed(self, filepath):
        if not os.path.exists(filepath):
            return
        
        file_size_mb = os.path.getsize(filepath) / (1024 * 1024)
        if file_size_mb >= self.config.max_file_size_mb:
            for i in range(self.config.backup_count - 1, 0, -1):
                src = "{}.{}".format(filepath, i)
                dst = "{}.{}".format(filepath, i + 1)
                if os.path.exists(src):
                    if os.path.exists(dst):
                        os.remove(dst)
                    os.rename(src, dst)
            
            backup_path = "{}.1".format(filepath)
            if os.path.exists(backup_path):
                os.remove(backup_path)
            os.rename(filepath, backup_path)
    
    def write_log(self, log_entry):
        service = log_entry.get("service", "unknown")
        filepath = self._get_log_file_path(service)
        combined_filepath = self._get_log_file_path(None)
        
        timestamp = log_entry.get("timestamp", datetime.utcnow().isoformat())
        level = log_entry.get("level", "INFO").upper()
        message = log_entry.get("message", "")
        request_id = log_entry.get("request_id", "N/A")
        
        formatted_line = self.config.log_format.format(
            timestamp=timestamp,
            level=level,
            service=service,
            request_id=request_id,
            message=message
        )
        
        extra = log_entry.get("extra", {})
        if extra:
            extra_str = " | extra: {}".format(json.dumps(extra))
            formatted_line = "{}{}".format(formatted_line, extra_str)
        
        formatted_line = "{}\n".format(formatted_line)
        
        with self._lock:
            self._rotate_if_needed(filepath)
            self._rotate_if_needed(combined_filepath)
            
            with open(filepath, "a", encoding="utf-8") as f:
                f.write(formatted_line)
            
            if filepath != combined_filepath:
                with open(combined_filepath, "a", encoding="utf-8") as f:
                    f.write(formatted_line)
        
        return formatted_line.strip()
    
    def read_logs(self, service_name=None, level=None, limit=100):
        filepath = self._get_log_file_path(service_name)
        if not os.path.exists(filepath):
            return []
        
        with self._lock:
            with open(filepath, "r", encoding="utf-8") as f:
                lines = f.readlines()
        
        if level:
            level_filter = "[{}]".format(level.upper())
            lines = [line for line in lines if level_filter in line]
        
        return [line.strip() for line in lines[-limit:]]


class LogRequestHandler(http.server.BaseHTTPRequestHandler):
    """HTTP request handler for log ingestion and retrieval."""
    
    log_writer = None
    valid_levels = {"DEBUG", "INFO", "WARNING", "ERROR", "CRITICAL"}
    
    def _set_response(self, status_code=200, content_type="application/json"):
        self.send_response(status_code)
        self.send_header("Content-Type", content_type)
        self.send_header("Access-Control-Allow-Origin", "*")
        self.send_header("Access-Control-Allow-Methods", "GET, POST, OPTIONS")
        self.send_header("Access-Control-Allow-Headers", "Content-Type, X-Service-Name, X-Request-ID")
        self.end_headers()
    
    def _read_body(self):
        content_length = int(self.headers.get("Content-Length", 0))
        if content_length == 0:
            return None
        body = self.rfile.read(content_length)
        return body.decode("utf-8")
    
    def _send_json(self, data, status_code=200):
        self._set_response(status_code)
        response = json.dumps(data)
        self.wfile.write(response.encode("utf-8"))
    
    def _validate_log_entry(self, entry):
        errors = []
        if not entry.get("message"):
            errors.append("'message' field is required")
        
        level = entry.get("level", "INFO").upper()
        if level not in self.valid_levels:
            errors.append("'level' must be one of: {}".format(", ".join(sorted(self.valid_levels))))
        
        return errors
    
    def do_OPTIONS(self):
        self._set_response(204)
    
    def do_POST(self):
        parsed_path = urlparse(self.path)
        
        if parsed_path.path == "/log":
            self._handle_single_log()
        elif parsed_path.path == "/logs/batch":
            self._handle_batch_logs()
        elif parsed_path.path == "/health":
            self._send_json({"status": "healthy", "timestamp": datetime.utcnow().isoformat()})
        else:
            self._send_json({"error": "Not found. Available endpoints: POST /log, POST /logs/batch, GET /logs"}, 404)
    
    def do_GET(self):
        parsed_path = urlparse(self.path)
        
        if parsed_path.path == "/logs":
            self._handle_get_logs(parsed_path)
        elif parsed_path.path == "/health":
            self._send_json({"status": "healthy", "timestamp": datetime.utcnow().isoformat()})
        elif parsed_path.path == "/services":
            self._handle_list_services()
        else:
            self._send_json({"error": "Not found. Available endpoints: POST /log, POST /logs/batch, GET /logs, GET /services"}, 404)
    
    def _handle_single_log(self):
        try:
            body = self._read_body()
            if not body:
                self._send_json({"error": "Request body is required"}, 400)
                return
            
            entry = json.loads(body)
            
            if "service" not in entry and self.headers.get("X-Service-Name"):
                entry["service"] = self.headers.get("X-Service-Name")
            
            if "request_id" not in entry and self.headers.get("X-Request-ID"):
                entry["request_id"] = self.headers.get("X-Request-ID")
            
            if "timestamp" not in entry:
                entry["timestamp"] = datetime.utcnow().isoformat()
            
            if "source_ip" not in entry:
                entry.setdefault("extra", {})["source_ip"] = self.client_address[0]
            
            errors = self._validate_log_entry(entry)
            if errors:
                self._send_json({"error": "Validation failed", "details": errors}, 400)
                return
            
            written = self.log_writer.write_log(entry)
            self._send_json({
                "status": "logged",
                "entry": written,
                "timestamp": entry["timestamp"]
            }, 201)
        
        except json.JSONDecodeError as e:
            self._send_json({"error": "Invalid JSON: {}".format(str(e))}, 400)
        except Exception as e:
            self._send_json({"error": "Internal server error: {}".format(str(e))}, 500)
    
    def _handle_batch_logs(self):
        try:
            body = self._read_body()
            if not body:
                self._send_json({"error": "Request body is required"}, 400)
                return
            
            data = json.loads(body)
            entries = data if isinstance(data, list) else data.get("logs", [])
            
            if not entries:
                self._send_json({"error": "No log entries provided"}, 400)
                return
            
            results = {"logged": 0, "failed": 0, "errors": []}
            
            for i, entry in enumerate(entries):
                if "service" not in entry and self.headers.get("X-Service-Name"):
                    entry["service"] = self.headers.get("X-Service-Name")
                
                if "request_id" not in entry and self.headers.get("X-Request-ID"):
                    entry["request_id"] = self.headers.get("X-Request-ID")
                
                if "timestamp" not in entry:
                    entry["timestamp"] = datetime.utcnow().isoformat()
                
                errors = self._validate_log_entry(entry)
                if errors:
                    results["failed"] += 1
                    results["errors"].append({"index": i, "errors": errors})
                    continue
                
                try:
                    self.log_writer.write_log(entry)
                    results["logged"] += 1
                except Exception as e:
                    results["failed"] += 1
                    results["errors"].append({"index": i, "errors": [str(e)]})
            
            status_code = 201 if results["failed"] == 0 else 207
            self._send_json(results, status_code)
        
        except json.JSONDecodeError as e:
            self._send_json({"error": "Invalid JSON: {}".format(str(e))}, 400)
        except Exception as e:
            self._send_json({"error": "Internal server error: {}".format(str(e))}, 500)
    
    def _handle_get_logs(self, parsed_path):
        try:
            params = parse_qs(parsed_path.query)
            service = params.get("service", [None])[0]
            level = params.get("level", [None])[0]
            limit = int(params.get("limit", [100])[0])
            
            limit = min(max(limit, 1), 10000)
            
            logs = self.log_writer.read_logs(
                service_name=service,
                level=level,
                limit=limit
            )
            
            self._send_json({
                "count": len(logs),
                "service": service or "all",
                "level_filter": level,
                "logs": logs
            })
        
        except ValueError as e:
            self._send_json({"error": "Invalid parameter: {}".format(str(e))}, 400)
        except Exception as e:
            self._send_json({"error": "Internal server error: {}".format(str(e))}, 500)
    
    def _handle_list_services(self):
        try:
            log_dir = self.log_writer.config.log_dir
            services = []
            default_log = self.log_writer.config.default_log_file
            
            if os.path.exists(log_dir):
                for filename in os.listdir(log_dir):
                    if filename.endswith(".log") and filename != default_log:
                        service_name = filename[:-4]  # Remove .log extension
                        filepath = os.path.join(log_dir, filename)
                        file_size = os.path.getsize(filepath)
                        services.append({
                            "name": service_name,
                            "log_file": filepath,
                            "size_bytes": file_size,
                            "size_mb": round(file_size / (1024 * 1024), 2)
                        })
            
            self._send_json({"services": services, "count": len(services)})
        
        except Exception as e:
            self._send_json({"error": "Internal server error: {}".format(str(e))}, 500)
    
    def log_message(self, format, *args):
        """Override to suppress default HTTP server logging to stderr."""
        timestamp = datetime.utcnow().isoformat()
        log_line = "[{}] [HTTP] {} - {}\n".format(
            timestamp,
            self.client_address[0],
            format % args
        )
        access_log_path = os.path.join(self.log_writer.config.log_dir, "access.log")
        with open(access_log_path, "a", encoding="utf-8") as f:
            f.write(log_line)


